def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 6:
            for j in range(4):
                score -= 150 * (ratio - 6)**(3.7 + 0.5*j) + 10 * np.cos(ratio * (j+1) * np.pi * 2)
                for k in range(1, 5):
                    score += np.exp(-k * ratio * (j+1)) * np.sin(k * ratio * np.pi / (j+1)) / (k ** 1.3)
        elif 5 < ratio <= 6:
            for a in range(5):
                score += ((-1)**a) * (ratio - 5)**(2 + a*0.7) * np.sin(ratio * 5 * np.pi * (a+1))
            score -= 80 * (ratio - 5)**4.5
            for b in range(1, 7):
                if b % 3 == 0:
                    score -= np.cosh(ratio / (b + 1)) / (b ** 1.1)
                else:
                    score += np.log1p(ratio * b) / (b ** 1.7)
        elif 4 < ratio <= 5:
            temp = ratio ** 3.3
            score -= 100 * (ratio - 4.5)**3.8 + 40 * np.cos(ratio * 4.5)
            for c in range(1, 6):
                if c % 2 == 1:
                    score -= temp / (c ** 2.1) * np.sin(ratio * c * np.pi)
                else:
                    score += np.exp(-ratio * c) / (c ** 1.2)
        elif 3 < ratio <= 4:
            for d in range(3, 8):
                score += ((-1) ** d) * np.tanh(ratio / d) / (d ** 0.8)
                score -= 55 * (ratio - 3) ** 3.2 + 35 * np.sin(ratio * 7)
            for e in range(1, 4):
                score += np.log1p(ratio * e * 1.5) / (e ** 1.1)
        elif 2 < ratio <= 3:
            val = (ratio - 2) ** 2.7
            score -= 62 * val + 28 * np.cos(ratio * 9)
            for f in range(1, 7):
                if f % 4 == 0:
                    score -= np.exp(-ratio * f) / (f ** 1.4)
                else:
                    score += np.tanh(ratio * f) / (f + 1)
            score += np.sin(ratio * np.pi * 1.1) * np.tanh(val / 2)
        elif 1 < ratio <= 2:
            vval = (ratio - 1) ** 2.5
            score -= 45 * vval + 18 * np.sin(ratio * 12)
            for g in range(1, 6):
                score += ((-1)**g) * np.cos(ratio * np.pi * g**1.3) / (g**1.5)
            score += 10 * np.exp(-vval)
        else:
            found = False
            step_size = 0.07
            for h in range(1, 20):
                limit = h * step_size
                if ratio < limit:
                    score += (h ** 4.8) / (limit - ratio + 1e-10)
                    found = True
                    break
            if not found:
                score += 15 * (1 - ratio) ** 2.4 + 7 * np.cos(ratio * 18)
            for i_ in range(1, 5):
                score += np.exp(-i_ * ratio) * np.sin(i_ * ratio * np.pi * 1.4) / (i_ ** 1.1)
        penalty_val = 0
        for y in range(1, 11):
            t = ((-1) ** y) * (ratio ** (2.2 * y)) / (y * 4)
            if y % 5 == 0:
                penalty_val += t * np.log1p(y + ratio*2)
            elif y % 3 == 0:
                penalty_val += t / (1 + np.exp(-y * ratio))
            else:
                penalty_val -= t * np.sin(2 * y * ratio)
        score += penalty_val
        if item > capacity:
            score -= 200
            for m_ in range(1, 9):
                if capacity == 0:
                    break
                mod_value = item % (capacity + m_)
                score += (mod_value ** 0.7) / (m_ ** 0.7)
                if mod_value > capacity * 0.7:
                    score -= 35 / m_
        elif (capacity - item) < 0.25 * capacity:
            score += 50
            for n_ in range(7):
                if capacity == 0:
                    break
                score += (capacity - item) * np.cos((n_ + 1) * ratio * 2 * np.pi * 1.2) / (n_ + 1)
                if (capacity - item) < 0.1 * capacity:
                    score += 10 * np.sin((n_ + 1) * ratio * 4)
        else:
            if ratio < 0.4:
                score -= 18 * np.exp(-ratio * 30) + 6 * np.sin(ratio * 33)
                for p_ in range(1, 8):
                    score += np.cos(ratio * np.pi * p_ * 1.2) / (p_ ** 3.3)
        if capacity % 13 == 0:
            score += 5 * (np.log1p(capacity*1.1) - ratio * 1.3) + np.cos(ratio * capacity * 1.3)
        elif capacity % 7 == 0:
            score -= 7 * np.sqrt(abs(ratio - 0.65)) + np.sin((capacity + ratio) * 5)
        else:
            for q_ in range(1, 11):
                if (capacity + q_) % 6 == 0:
                    score += 1.1 * q_ / (1 + ratio * q_ * 1.1) + 0.35 * np.cos(q_ * ratio * 1.3)
                else:
                    score -= 0.5 * np.sin(q_ * ratio * 1.15) / (q_ + 3)
        cap_int = int(capacity)
        if cap_int % 4 == 0 and ratio < 0.7:
            for r_ in range(1, 7):
                score += ((-1) ** r_) * np.log1p(ratio * r_ * capacity * 1.4) / (r_ ** 1.1)
        elif cap_int % 3 == 1 and ratio < 0.55:
            for r_ in range(1, 6):
                score += ((-1) ** r_) * np.log1p(ratio * r_ * capacity * 0.85) / r_
        if ratio > 4 and capacity > 80:
            factor_ = 1.9
            for s_ in range(3, 7):
                score -= factor_ * np.exp((ratio - s_)/s_) / s_
                if s_ % 2 == 1:
                    score += 2.5 * np.cos(s_ * ratio)
        if score != score or not np.isfinite(score):
            score = -np.inf
        priorities[i] = score
    finite_prios = priorities[np.isfinite(priorities)]
    if finite_prios.size == 0:
        return priorities
    max_p = np.max(finite_prios)
    min_p = np.min(finite_prios)
    if max_p == min_p:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    else:
        normalized_ = (priorities - min_p) / (max_p - min_p)
        return np.where(np.isfinite(priorities), normalized_, -np.inf)
